import{_ as i,o as r,c as a,a2 as d}from"./chunks/framework.Cuq8tsM6.js";const u=JSON.parse('{"title":"Display Email","description":"","frontmatter":{"title":"Display Email"},"headers":[],"relativePath":"docs/fr/advertisers/display-email/index.md","filePath":"docs/fr/advertisers/display-email/index.md"}'),n={name:"docs/fr/advertisers/display-email/index.md"};function t(s,e,o,p,l,v){return r(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="encart-newsletter-display-email" tabindex="-1">Encart Newsletter (Display Email) <a class="header-anchor" href="#encart-newsletter-display-email" aria-label="Permalink to &quot;Encart Newsletter (Display Email)&quot;">​</a></h1><p>Insérez une bannière publicitaire au sein des communications d&#39;un partenaire. Un format de notoriété efficace et non intrusif.</p><div><a href="workflow" class="btn btn-primary mr-2">Voir le Process</a><a href="specs" class="btn btn-outline">Specs Bannières</a></div><hr><h2>Où diffuser votre bannière ?</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;width:100%;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>📢 Blast (Newsletter Édito)</h3><p>Votre bannière s&#39;insère dans la newsletter hebdomadaire du média ou de l&#39;e-commerçant.</p><p><em>Ex: Header ou Cœur de contenu.</em></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>🛍️ Post-Purchase (Transac)</h3><p>Votre bannière apparaît dans l&#39;email de confirmation de commande ou de livraison.</p><p><em>Ex: &quot;Profitez de cette offre partenaire en attendant votre colis&quot;.</em></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3>👋 Welcome Email</h3><p>Présence dans l&#39;email de bienvenue envoyé aux nouveaux inscrits.</p><p><em>Ex: Encart en bas de mail pour une offre complémentaire.</em></p></div></div><h2>Pourquoi choisir ce format ?</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:250px;border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-soft);"><h3>⚡ Simplicité de Production</h3><p>Contrairement à l&#39;email dédié, <strong>vous ne fournissez qu&#39;une image</strong>. Pas besoin de coder un email HTML complet.</p></div><div style="flex:1;min-width:250px;border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-soft);"><h3>🛡️ Non Intrusif</h3><p>Votre marque s&#39;insère dans un contenu que l&#39;abonné attend, sans perturber sa lecture.</p></div></div><h2>Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🌐</div><div><h3>Inventaire Unifié</h3><p>Plus besoin de négocier avec chaque média ou e-commerçant. Accédez à un inventaire fragmenté de <strong>+250 partenaires</strong> via une seule plateforme.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🛡️</div><div><h3>Brand Safety &amp; Contexte</h3><p>Contrairement au Display programmatique (open web), votre marque s&#39;affiche ici dans un environnement <strong>fermé, sûr et cautionné</strong> par l&#39;éditeur (la marque partenaire).</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">📊</div><div><h3>Tracking Centralisé</h3><p>Nous générons et uniformisons les liens de tracking pour toutes vos campagnes. Suivez les clics de 10 newsletters différentes sur un seul tableau de bord.</p></div></div></div>',10)])])}const m=i(n,[["render",t]]);export{u as __pageData,m as default};
